class Solution {
public:
    bool uniqueOccurrences(vector<int>& arr) {
        unordered_map<int, int> countMap;
        for (int num : arr) {
            countMap[num]++;
        }
        unordered_set<int> occurrenceSet;
        for (auto& pair : countMap) {
            if (!occurrenceSet.insert(pair.second).second) {
                return false;
            }
        }
        return true;
    }
};
